const filas = $input.all().map(i => i.json);

let nombreArchivo = '';
try {
  nombreArchivo = $('Convert Spreadsheet').item.json.name || '';
} catch(e) {
  try {
    nombreArchivo = $('Preparar GSheet').item.json.name || '';
  } catch(e2) {
    nombreArchivo = $('Resolver File ID Final').first().json.name || '';
  }
}

const ticketId = $('Resolver File ID Final').first().json.ticketId || null;

const filasFiltradas = filas.filter(fila =>
  Object.values(fila).filter(v =>
    v !== '' && v !== null && v !== undefined && String(v).trim() !== ''
  ).length >= 2
);

const texto = filasFiltradas
  .map(fila => Object.entries(fila)
    .map(([k, v]) => `${k}: ${v}`)
    .join(' | '))
  .join('\n');

return [{ json: { textoSpreadsheet: texto, NOMBRE_ARCHIVO: nombreArchivo, ticketId: ticketId } }];

const items = $input.all();
const ticketId = $input.first().json.ticketId || $('Get Ticket Properties').first().json.ticketId;
const fechaInicio = $('Get Ticket Properties').first().json.FECHA_INICIO;

const todos = items.map(i => i.json).filter(f => {
  const mime = f.mimeType || '';
  return mime !== 'application/vnd.google-apps.folder';
});

const esDoc = (f) => {
  const name = (f.name || '').toLowerCase();
  const mime = f.mimeType || '';
  return (
    mime === 'application/pdf' ||
    mime === 'application/vnd.google-apps.spreadsheet' ||
    mime === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
    name.endsWith('.pdf') ||
    name.endsWith('.xlsx') ||
    name.endsWith('.xls')
  );
};

const esImg = (f) => {
  const name = (f.name || '').toLowerCase();
  const mime = f.mimeType || '';
  return (
    mime === 'image/jpeg' ||
    mime === 'image/png' ||
    name.endsWith('.jpg') ||
    name.endsWith('.jpeg') ||
    name.endsWith('.png')
  );
};

const docs = todos.filter(esDoc);
const imgs = todos.filter(esImg);

const mesesAliases = {
  '01': ['enero', 'ene', 'janeiro', 'jan', 'january'],
  '02': ['febrero', 'feb', 'fevereiro', 'fev', 'february'],
  '03': ['marzo', 'mar', 'março', 'marco', 'march'],
  '04': ['abril', 'abr', 'april', 'apr'],
  '05': ['mayo', 'may', 'maio', 'mai'],
  '06': ['junio', 'jun', 'junho', 'june'],
  '07': ['julio', 'jul', 'julho', 'july'],
  '08': ['agosto', 'ago', 'agost', 'august', 'aug'],
  '09': ['septiembre', 'setiembre', 'sep', 'sept', 'setembro', 'set', 'september'],
  '10': ['octubre', 'oct', 'outubro', 'out', 'october'],
  '11': ['noviembre', 'nov', 'novembro', 'november'],
  '12': ['diciembre', 'dic', 'dezembro', 'dez', 'december', 'dec']
};

const normalizar = (str) => str.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const matcheaMes = (nombre, aliases) => {
  const nombreNorm = normalizar(nombre || '');
  return aliases.some(alias => {
    const aliasNorm = normalizar(alias);
    const regex = new RegExp(`(^|[^a-z])${aliasNorm}([^a-z]|$)`, 'i');
    return regex.test(nombreNorm);
  });
};

const ultimoModificado = (lista) => {
  return [...lista].sort((a, b) => new Date(b.modifiedTime) - new Date(a.modifiedTime))[0];
};

const pendienteResponse = (motivo) => {
  const folderId = $('Get Ticket Properties').first().json.id;
  const link = $('Get Ticket Properties').first().json.originalUrl;
  return [{ json: { __pendiente: true, motivo: motivo, ticketId: ticketId, link: link, folderId: folderId } }];
};

const archivoResponse = (archivo) => {
  const name = (archivo.name || '').toLowerCase();
  return [{ json: {
    id: archivo.id,
    name: archivo.name || '',
    mimeType: archivo.mimeType || '',
    esPDF: archivo.mimeType === 'application/pdf' || name.endsWith('.pdf'),
    esSpreadsheet: archivo.mimeType === 'application/vnd.google-apps.spreadsheet' || name.endsWith('.xlsx') || name.endsWith('.xls'),
    esImagen: archivo.mimeType === 'image/jpeg' || archivo.mimeType === 'image/png' || name.endsWith('.jpg') || name.endsWith('.jpeg') || name.endsWith('.png'),
    ticketId: ticketId
  } }];
};

if (todos.length === 0) return pendienteResponse('carpeta_vacia');

if (docs.length > 0) {
  if (docs.length === 1) return archivoResponse(docs[0]);
  if (!fechaInicio) throw new Error('Hay varios documentos pero el ticket no tiene FECHA_INICIO cargada.');
  const mes = fechaInicio.substring(5, 7);
  const aliases = mesesAliases[mes];
  if (!aliases) throw new Error(`Mes inválido en FECHA_INICIO: ${fechaInicio}`);
  const matches = docs.filter(f => matcheaMes(f.name, aliases));
  if (matches.length === 0) return pendienteResponse('sin_match_mes');
  if (matches.length === 1) return archivoResponse(matches[0]);
  return archivoResponse(ultimoModificado(matches));
}

if (imgs.length > 0) {
  if (fechaInicio) {
    const mes = fechaInicio.substring(5, 7);
    const aliases = mesesAliases[mes];
    if (aliases) {
      const matches = imgs.filter(f => matcheaMes(f.name, aliases));
      if (matches.length === 1) return archivoResponse(matches[0]);
      if (matches.length > 1) return archivoResponse(ultimoModificado(matches));
    }
  }
  return archivoResponse(ultimoModificado(imgs));
}

return pendienteResponse('sin_match_mes');

const body = $input.item.json.body;
const events = Array.isArray(body) ? body : [body];
const evento = events.find(e => e.propertyName === 'hs_pipeline_stage');
if (!evento) return [{ json: { skip: true, motivo: 'Evento no es cambio de stage' } }];
return [{ json: { skip: false, ticketId: evento.objectId } }];

const base64Data = $input.item.json.base64PDF;
const apiKey = '{{GOOGLE_API_KEY}}';

const downloadInfo = $('Download file').item.json;
const fileName = (downloadInfo.name || '').toLowerCase();
let mimeType;
if (fileName.endsWith('.pdf')) mimeType = 'application/pdf';
else if (fileName.endsWith('.png')) mimeType = 'image/png';
else if (fileName.endsWith('.jpg') || fileName.endsWith('.jpeg')) mimeType = 'image/jpeg';
else mimeType = downloadInfo.mimeType || 'application/pdf';

const esImagen = mimeType.startsWith('image/');
const fechaInicio = $('Get Ticket Properties').first().json.FECHA_INICIO || '';
const anioTicket = fechaInicio.substring(0, 4);
const mesTicket = fechaInicio.substring(5, 7);
const mesesNombres = {
  '01': 'enero', '02': 'febrero', '03': 'marzo', '04': 'abril',
  '05': 'mayo', '06': 'junio', '07': 'julio', '08': 'agosto',
  '09': 'septiembre', '10': 'octubre', '11': 'noviembre', '12': 'diciembre'
};
const nombreMesTicket = mesesNombres[mesTicket] || '';

const promptOC = `Sos un asistente experto en extracción de datos de documentos de compra de medios (PI - Plano de Investimento u Orden de Publicidad). El documento puede ser una tabla escaneada o con texto. Devolvé ÚNICAMENTE el siguiente JSON sin texto adicional ni backticks ni explicaciones:\n\n{"RAZON_SOCIAL":"","TAX_ID":"","PAIS":"","MONEDA":"","VALOR_FACTURAR":0.0,"PERIODO_CAMPANA":"YYYY-MM","NRO_ORDEN":"","NRO_PLAN_PAUTA":"","MEDIO":"","PRODUCTO":"","CONTACTO_FACTURA":"NULL","NRO_CONTRATO":"NULL","NRO_PRESUPUESTO":"NULL"}\n\nINSTRUCCIONES:\n1. RAZON_SOCIAL: buscá "Faturar para (Razão Social)", "Faturar para", "Razón Social", "Anunciante".\n2. TAX_ID: buscá "Nro. Documento Fiscal", "CUIT", "CNPJ", "RFC", "RUT". Si no hay, usá NULL.\n3. PAIS: determiná por moneda o dirección.\n4. MONEDA: convertí al código ISO.\n5. VALOR_FACTURAR: buscá "Total da Inversão", "Total de la Inversión", "Costo Neto Total".\n6. PERIODO_CAMPANA: fecha de inicio de campaña en formato YYYY-MM.\n7. NRO_ORDEN: buscá "Nro de Orden", "N° Orden", "Número de Orden".\n8. NRO_PLAN_PAUTA: buscá "Plan", "Pauta", "Nro Plan", "NCID".\n9. MEDIO: buscá "Medio", "Canal".\n10. PRODUCTO: buscá "Producto", "Campanha", "Campaña".\n11. CONTACTO_FACTURA: buscá "E-mail", "Email", "Correo". Si no hay, usá NULL.\n12. NRO_CONTRATO: si no hay, usá NULL.\n13. NRO_PRESUPUESTO: si no hay, usá NULL.\n14. Devolvé SOLO el JSON.`;

const promptImagen = `La imagen adjunta es una captura sobre una compra de medios publicitarios.\n\nCONTEXTO: campaña de ${nombreMesTicket} ${anioTicket}. Extraé SOLO datos de ese mes.\n\nDevolvé ÚNICAMENTE JSON:\n{"RAZON_SOCIAL":"","TAX_ID":"","PAIS":"","MONEDA":"","VALOR_FACTURAR":0.0,"NRO_ORDEN":"","NRO_PLAN_PAUTA":"","MEDIO":"","PRODUCTO":"","CONTACTO_FACTURA":"NULL","NRO_CONTRATO":"NULL","NRO_PRESUPUESTO":"NULL"}`;

const promptElegido = esImagen ? promptImagen : promptOC;

const geminiResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: `{{GEMINI_API_URL}}`,
  headers: { 'content-type': 'application/json' },
  body: JSON.stringify({
    contents: [{ parts: [{ inline_data: { mime_type: mimeType, data: base64Data } }, { text: promptElegido }] }]
  })
});

const text = geminiResponse.candidates[0].content.parts[0].text;
const jsonMatch = text.match(/\{[\s\S]*\}/);
const clean = jsonMatch ? jsonMatch[0] : text;
let parsed;
try { parsed = JSON.parse(clean); } catch(e) { return { json: { raw: text, clean: clean, error: e.message } }; }
parsed.PRODUCTO = parsed.PRODUCTO || parsed.PRODUTO || 'NULL';
delete parsed.PRODUTO;
parsed.NRO_ORDEN = parsed.NRO_ORDEN || parsed.NRO_ORDEM || 'NULL';
delete parsed.NRO_ORDEM;
if (esImagen && fechaInicio) parsed.PERIODO_CAMPANA = `${anioTicket}-${mesTicket}`;
parsed.NOMBRE_ARCHIVO = $('Download file').item.json.name || '';
parsed.ticketId = $('Download file').item.json.ticketId || null;
return { json: parsed };

return $input.all().map(item => {
  const name = (item.json.name || '').toLowerCase();
  const mimeType = item.json.mimeType || '';
  const esXLSX = name.endsWith('.xlsx') || name.endsWith('.xls') || mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
  const esGoogleSheet = mimeType === 'application/vnd.google-apps.spreadsheet';
  return { json: { ...item.json, tipoArchivo: esXLSX ? 'xlsx' : esGoogleSheet ? 'gsheet' : 'desconocido' } };
});

const sheets = $input.item.json.sheets;
const spreadsheetId = $input.item.json.spreadsheetId;
const primeraVisible = sheets.find(s => !s.properties.hidden);
return [{ json: { spreadsheetId, sheetId: primeraVisible.properties.sheetId, sheetTitle: primeraVisible.properties.title } }];

const texto = $input.item.json.textoSpreadsheet;
const nombreArchivo = $input.item.json.NOMBRE_ARCHIVO || '';

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: '{{ANTHROPIC_API_URL}}',
  headers: {
    'content-type': 'application/json',
    'x-api-key': '{{ANTHROPIC_API_KEY}}',
    'anthropic-version': '2023-06-01'
  },
  body: JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    messages: [{
      role: 'user',
      content: `Sos un asistente experto en extracción de datos. Analizá el documento y devolvé ÚNICAMENTE el siguiente JSON sin texto adicional ni backticks:\n\n{"RAZON_SOCIAL":"","TAX_ID":"","PAIS":"","MONEDA":"","VALOR_FACTURAR":0.0,"PERIODO_CAMPANA":"YYYY-MM","NRO_ORDEN":"","NRO_PLAN_PAUTA":"","MEDIO":"","PRODUCTO":"","CONTACTO_FACTURA":"NULL","NRO_CONTRATO":"NULL","NRO_PRESUPUESTO":"NULL"}\n\nContenido del documento:\n${texto}`
    }]
  })
});

const text = response.content[0].text;
const clean = text.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(clean);
parsed.NOMBRE_ARCHIVO = nombreArchivo;
parsed.ticketId = $input.item.json.ticketId || null;
return [{ json: parsed }];

const ticketId = $input.item.json.ticketId;
const token = '{{HUBSPOT_PAT_TOKEN}}';

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: `{{HUBSPOT_API_URL}}`,
  qs: {
    properties: 'fecha_de_inicio,fecha_de_finalizaci_n,ciclo_numero,deal_id,link_orden_de_publicidad_op,campaignid_kite'
  },
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
  },
  json: true
});

const props = response.properties || {};
const url = props.link_orden_de_publicidad_op || '';

if (!url || (!url.includes('drive.google.com') && !url.includes('docs.google.com'))) {
  return [{ json: { ...$input.item.json, skip: true, motivo: 'Ticket sin link válido: ' + url } }];
}

const esCarpeta = url.includes('/drive/folders/') || url.includes('/folders/');
let id = null;
if (esCarpeta) {
  const m = url.match(/folders\/([a-zA-Z0-9_-]+)/);
  if (m) id = m[1];
} else {
  const mFile = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
  const mOpen = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  const mDocs = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (mFile) id = mFile[1];
  else if (mOpen) id = mOpen[1];
  else if (mDocs) id = mDocs[1];
}

if (!id) return [{ json: { ...$input.item.json, skip: true, motivo: 'No se pudo extraer ID del link: ' + url } }];

return [{ json: {
  ...$input.item.json,
  id, esCarpeta, originalUrl: url, skip: false,
  FECHA_INICIO: props.fecha_de_inicio || null,
  FECHA_FIN: props.fecha_de_finalizaci_n || null,
  CICLO_NUMERO: props.ciclo_numero || null,
  DEAL_ID_HUBSPOT: props.deal_id || null,
  CAMPAIGN_ID_KITE: props.campaignid_kite || null
} }];

const archivos = $input.first().json.files || [];
const ticketId = $('Get Ticket Properties').first().json.ticketId;
const folderId = $('Get Ticket Properties').first().json.id;
const link = $('Get Ticket Properties').first().json.originalUrl;
if (archivos.length === 0) return [{ json: { __pendiente: true, motivo: 'carpeta_vacia', ticketId, link, folderId } }];
return archivos.map(f => ({ json: { id: f.id, name: f.name, mimeType: f.mimeType, modifiedTime: f.modifiedTime } }));
